 1	import * as React from 'react';
 2	import { Form, PageSection } from '@patternfly/react-core';
 3	import { FormikProps, FormikValues, getIn } from 'formik';
 4	import * as _ from 'lodash';
 5	import { useTranslation } from 'react-i18next';
 6	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 7	import PipelineParameters from './PipelineParameters';
 8	import FormFooter from './multi-column-field/FormFooter';
 9	
10	type PipelineParametersFormProps = FormikProps<FormikValues> & {
11	  namespace: string;
12	};
13	
14	const PipelineParametersForm: React.FC<PipelineParametersFormProps> = ({
15	  namespace,
16	  handleSubmit,
17	  handleReset,
18	  isSubmitting,
19	  status,
20	  errors,
21	  dirty,
22	}) => {
23	  const pipelineParameterAccess = useAccessReview({
24	    group: 'tekton.dev',
25	    resource: 'pipelines',
26	    namespace,
27	    verb: 'update',
28	  });
29	  const { t } = useTranslation('plugin__pipelines-console-plugin');
30	  const disableSubmit =
31	    !dirty || !_.isEmpty(_.compact(getIn(errors, 'parameters')));
32	  return (
33	    <Form onSubmit={handleSubmit}>
34	      <PageSection
35	        isFilled
36	        variant="light"
37	        className="pipelines-console-plugin__page-section-width pf-v6-u-p-0 pipelines-console-plugin__background-transparent"
38	      >
39	        <PipelineParameters
40	          fieldName="parameters"
41	          isReadOnly={!pipelineParameterAccess}
42	          addLabel={t('Add Pipeline parameter')}
43	          nameLabel={t('Name')}
44	          nameFieldName="name"
45	          descriptionLabel={t('Description')}
46	          descriptionFieldName="description"
47	          valueLabel={t('Default value')}
48	          valueFieldName="default"
49	          emptyMessage={t('No parameters are associated with this Pipeline.')}
50	          emptyValues={{ name: '', description: '', default: '' }}
51	          className="pipelines-console-plugin__background-transparent"
52	        />
53	      </PageSection>
54	      {pipelineParameterAccess && (
55	        <FormFooter
56	          handleReset={handleReset}
57	          isSubmitting={isSubmitting}
58	          errorMessage={status && status.submitError}
59	          successMessage={status && !dirty && status.success}
60	          disableSubmit={disableSubmit}
61	          showAlert={!disableSubmit}
62	          submitLabel={t('Save')}
63	          resetLabel={t('Reload')}
64	          sticky
65	        />
66	      )}
67	    </Form>
68	  );
69	};
70	
71	export default PipelineParametersForm;

